        role=msg.get('role') or o.get('role')
        content=msg.get('content')
        texts=[]
        if isinstance(content,str):
            texts=[content]
        elif isinstance(content,list):
            for c in content:
                if isinstance(c,dict) and c.get('type')=='text':
                    texts.append(c.get('text',''))
                elif isinstance(c,dict) and c.get('type')=='tool_use':
                    name=c.get('name','')
                    inp=c.get('input') or {}
                    if name in ('Shell','Write','StrReplace') or 'save_project' in name.lower() or 'project' in json.dumps(inp)[:300].lower():
                        # only interesting shells
                        cmd=inp.get('command','') or inp.get('contents','') or inp.get('path','') or str(inp)[:200]
                        if any(k in (cmd+name).lower() for k in ['seed','project_master','relocation-jobs','save_project']):
                            texts.append(f'TOOL {name}: {str(cmd)[:800]}')
        text='\n'.join(texts)
        if not text: continue
        low=text.lower()
        if role=='user' and any(k in low for k in ['project','master','write-up','relocation','seed']):
            print(f'USER L{i}: {text[:1500]}\n')
        if role=='assistant' and any(k in low for k in ['seeded','save_project_master','relocation-jobs','project master']):
            # prefer shorter summary-like
            if len(text)<3000 or 'seed' in low or 'slug' in low:
                print(f'ASST L{i} ({len(text)} chars): {text[:2000]}\n')
